78	// TierCandidate is one (harness, model) pair to try for a ladder tier.
79	// It is produced by ResolveTierCandidates and consumed by the escalation
80	// loop in execute-loop. Source carries the provenance (override|catalog) so
81	// diagnostics can distinguish caller-provided overrides from defaults.
82	type TierCandidate struct {
83		Surface string // catalog surface (empty for override candidates)
84		Harness string // harness name (empty for override candidates — upstream picks)
85		Model   string // concrete model string to pass to ResolveRoute
86		Source  string // "override" or "catalog"
87	}
