89	// catalogSurfaceOrder is the deterministic order surfaces are tried within a
90	// tier. Walking surfaces in a stable order makes tier-attempt diagnostics
91	// reproducible across runs.
92	var catalogSurfaceOrder = []string{"codex", "claude", "embedded-openai"}
93	
94	// surfaceToHarnessName returns the harness name that owns a catalog surface.
95	// Inverse of harnessToSurface.
96	func surfaceToHarnessName(surface string) string {
97		for h, s := range harnessToSurface {
98			if s == surface {
99				return h
100			}
101		}
102		return ""
103	}
104	
105	// ResolveTierCandidates returns ordered (harness, model) candidates for a
106	// ladder tier. agent.routing.model_overrides wins when set (an override has
107	// no associated harness — upstream picks); catalog surfaces in
108	// catalogSurfaceOrder follow as defaults so projects without
109	// model_overrides still resolve a concrete model per tier via the catalog.
110	//
111	// Healthy-harness and provider-reachability checks are NOT performed here:
112	// callers should iterate the returned candidates and probe each via
113	// svc.ResolveRoute / svc.RouteStatus, recording per-candidate rejections in
114	// tier-attempt diagnostics. ResolveTierCandidates is purely the "what could
115	// be tried" enumeration.
116	func ResolveTierCandidates(routing *config.RoutingConfig, cat *Catalog, tier escalation.ModelTier) []TierCandidate {
117		var out []TierCandidate
118		tierStr := string(tier)
119	
120		if routing != nil && routing.ModelOverrides != nil {
121			if override := strings.TrimSpace(routing.ModelOverrides[tierStr]); override != "" {
122				out = append(out, TierCandidate{Model: override, Source: "override"})
123			}
124		}
125	
126		if cat == nil {
127			cat = BuiltinCatalog
128		}
129		if entry, ok := cat.Entry(tierStr); ok {
130			for _, surface := range catalogSurfaceOrder {
131				model, ok := entry.Surfaces[surface]
132				if !ok || strings.TrimSpace(model) == "" {
133					continue
134				}
135				if cat.IsBlockedModelID(model) {
136					continue
137				}
138				harness := surfaceToHarnessName(surface)
139				if harness == "" {
140					continue
141				}
142				out = append(out, TierCandidate{
143					Surface: surface,
144					Harness: harness,
145					Model:   model,
146					Source:  "catalog",
147				})
148			}
149		}
150		return out
151	}
