153	func tierWithinBounds(tier, minTier, maxTier string) bool {
154		rank, ok := profileTierRank[tier]
155		if !ok {
156			return minTier == "" && maxTier == ""
157		}
158		if minTier != "" {
159			if minRank, ok := profileTierRank[minTier]; ok && rank < minRank {
160				return false
161			}
162		}
163		if maxTier != "" {
164			if maxRank, ok := profileTierRank[maxTier]; ok && rank > maxRank {
165				return false
166			}
167		}
168		return true
169	}
