45	// workerDispatchAdapter implements GraphQL action dispatch using the live
46	// WorkerManager.
47	type workerDispatchAdapter struct {
48		manager *WorkerManager
49	}
50	
51	func (a *workerDispatchAdapter) DispatchWorker(ctx context.Context, kind string, projectRoot string, rawArgs *string) (*ddxgraphql.WorkerDispatchResult, error) {
52		if a == nil || a.manager == nil {
53			return nil, fmt.Errorf("worker dispatcher is not configured")
54		}
55		if err := ctx.Err(); err != nil {
56			return nil, err
57		}
58		if kind != "execute-loop" {
59			return nil, fmt.Errorf("unsupported worker kind %q", kind)
60		}
61	
62		var req struct {
63			Harness       string `json:"harness"`
64			Model         string `json:"model"`
65			Profile       string `json:"profile"`
66			Provider      string `json:"provider"`
67			ModelRef      string `json:"model_ref"`
68			Effort        string `json:"effort"`
69			LabelFilter   string `json:"label_filter"`
70			Once          bool   `json:"once"`
71			PollInterval  string `json:"poll_interval"`
72			NoReview      bool   `json:"no_review"`
73			ReviewHarness string `json:"review_harness"`
74			ReviewModel   string `json:"review_model"`
75			MinTier       string `json:"min_tier"`
76			MaxTier       string `json:"max_tier"`
77		}
78		if rawArgs != nil && *rawArgs != "" {
79			if err := json.Unmarshal([]byte(*rawArgs), &req); err != nil {
80				return nil, fmt.Errorf("invalid worker args JSON: %w", err)
81			}
82		}
83	
84		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
85		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
86		// for this project so the "+ Add worker" button can refuse cleanly.
87		if wc := loadWorkersConfig(projectRoot); wc != nil {
88			if spec := wc.DefaultSpec; spec != nil {
89				if req.Harness == "" {
90					req.Harness = spec.Harness
91				}
92				if req.Profile == "" {
93					req.Profile = spec.Profile
94				}
95				if req.Effort == "" {
96					req.Effort = spec.Effort
97				}
98				if req.MinTier == "" {
99					req.MinTier = spec.MinTier
100				}
101				if req.MaxTier == "" {
102					req.MaxTier = spec.MaxTier
103				}
104			}
105			if wc.MaxCount != nil && *wc.MaxCount >= 0 {
106				running := a.countRunningDrainWorkers(projectRoot)
107				if running >= *wc.MaxCount {
108					return nil, fmt.Errorf("workers.max_count cap reached: %d running (limit %d)", running, *wc.MaxCount)
109				}
110			}
111		}
112	
113		// Default-path contract (ddx-755f5881 AC #1): an empty dispatch input
114		// (no rawArgs, no workers.default_spec) must produce a spec with
115		// Profile: "default" and nothing else. This eliminates the historical
116		// 19-burn drain-queue failure mode where an empty spec fanned out into
117		// per-tier ladder iteration with no upstream synthesis target.
118		if req.Profile == "" {
119			req.Profile = "default"
120		}
121	
122		var pollInterval time.Duration
123		if req.PollInterval != "" {
124			d, err := time.ParseDuration(req.PollInterval)
125			if err != nil {
126				return nil, fmt.Errorf("invalid poll_interval: %w", err)
127			}
128			pollInterval = d
129		}
130	
131		record, err := a.manager.StartExecuteLoop(ExecuteLoopWorkerSpec{
132			ProjectRoot:   projectRoot,
133			Harness:       req.Harness,
134			Model:         req.Model,
135			Profile:       req.Profile,
136			Provider:      req.Provider,
137			ModelRef:      req.ModelRef,
138			Effort:        req.Effort,
139			LabelFilter:   req.LabelFilter,
140			Once:          req.Once,
141			PollInterval:  pollInterval,
142			NoReview:      req.NoReview,
143			ReviewHarness: req.ReviewHarness,
144			ReviewModel:   req.ReviewModel,
145			MinTier:       req.MinTier,
146			MaxTier:       req.MaxTier,
147		})
148		if err != nil {
149			return nil, err
150		}
151		return &ddxgraphql.WorkerDispatchResult{
152			ID:    record.ID,
153			State: record.State,
154			Kind:  record.Kind,
155		}, nil
156	}
