172	// countRunningDrainWorkers counts execute-loop workers currently in state
173	// "running" for projectRoot. Returns 0 on any error.
174	func (a *workerDispatchAdapter) countRunningDrainWorkers(projectRoot string) int {
175		if a == nil || a.manager == nil {
176			return 0
177		}
178		recs, err := a.manager.List()
179		if err != nil {
180			return 0
181		}
182		count := 0
183		for _, rec := range recs {
184			if rec.Kind == "execute-loop" && rec.State == "running" && rec.ProjectRoot == projectRoot {
185				count++
186			}
187		}
188		return count
189	}
