191	func (a *workerDispatchAdapter) DispatchPlugin(ctx context.Context, projectRoot string, name string, action string, scope string) (*ddxgraphql.PluginDispatchResult, error) {
192		if a == nil || a.manager == nil {
193			return nil, fmt.Errorf("worker dispatcher is not configured")
194		}
195		if err := ctx.Err(); err != nil {
196			return nil, err
197		}
198		record, err := a.manager.StartPluginAction(PluginActionWorkerSpec{
199			ProjectRoot: projectRoot,
200			Name:        name,
201			Action:      action,
202			Scope:       scope,
203		}, func(runCtx context.Context) (string, error) {
204			if err := runCtx.Err(); err != nil {
205				return "", err
206			}
207			return ddxgraphql.DispatchPluginAction(projectRoot, name, action)
208		})
209		if err != nil {
210			return nil, err
211		}
212		return &ddxgraphql.PluginDispatchResult{
213			ID:     record.ID,
214			State:  record.State,
215			Action: action,
216		}, nil
217	}
