219	func (a *workerDispatchAdapter) StopWorker(ctx context.Context, id string) (*ddxgraphql.WorkerLifecycleResult, error) {
220		if a == nil || a.manager == nil {
221			return nil, fmt.Errorf("worker dispatcher is not configured")
222		}
223		if err := ctx.Err(); err != nil {
224			return nil, err
225		}
226		if err := a.manager.Stop(id); err != nil {
227			return nil, err
228		}
229		rec, err := a.manager.Show(id)
230		if err != nil {
231			return &ddxgraphql.WorkerLifecycleResult{ID: id, State: "stopping", Kind: "execute-loop"}, nil
232		}
233		return &ddxgraphql.WorkerLifecycleResult{
234			ID:    rec.ID,
235			State: rec.State,
236			Kind:  rec.Kind,
237		}, nil
238	}
