158	// loadWorkersConfig reads .ddx/config.yaml at projectRoot and returns the
159	// workers block, or nil when unset / on error. Errors are swallowed because
160	// a missing or malformed config must not block the dispatch path.
161	func loadWorkersConfig(projectRoot string) *config.WorkersConfig {
162		if projectRoot == "" {
163			return nil
164		}
165		cfg, err := config.LoadWithWorkingDir(projectRoot)
166		if err != nil || cfg == nil {
167			return nil
168		}
169		return cfg.Workers
170	}
